def build_translator() -> LLMTranslator:
    return LLMTranslator(
        api_key=os.environ["OPENAI_API_KEY"],
        base_url=os.environ.get("OPENAI_BASE_URL"),
        model=os.environ.get("OPENAI_MODEL", "gpt-4o-mini"),
        max_chunk_chars=int(os.environ.get("TRANSLATE_MAX_CHUNK_CHARS", "1000")),
        max_concurrent=int(os.environ.get("TRANSLATE_MAX_CONCURRENT", "3")),
        max_retries=int(os.environ.get("TRANSLATE_MAX_RETRIES", "2")),
    )


def estimate_html_request_count(translator: LLMTranslator, html: str) -> tuple[int, int]:
    nodes = extract_text_nodes(BeautifulSoup(html, "html.parser"))
    request_count = 0
    current_size = 0
    for node in nodes:
        item_size = len(node.text) + 32
        if current_size and current_size + item_size > translator.config.max_chunk_chars:
            request_count += 1
            current_size = 0
        current_size += item_size
    if current_size:
        request_count += 1
    return len(nodes), request_count


async def main() -> None:
    translator = build_translator()

    print("=== Plain text ===")
    text_result = translator.translate_document(
        TEXT,
        source_lang="en",
        target_lang="zh-CN",
    )
    print(text_result.text)

    print("\n=== Markdown ===")
    markdown_result = translator.translate_document(
        MARKDOWN_TEXT,
        source_lang="en",
        target_lang="zh-CN",
        format="markdown",
    )
    print(markdown_result.text)

    print("\n=== HTML async chunk translation ===")
    html_node_count, html_request_count = estimate_html_request_count(translator, HTML_TEXT)
    print(f"HTML text nodes: {html_node_count}")
    print(f"Estimated HTML requests: {html_request_count}, max_concurrent={translator.config.max_concurrent}")
    html_result = await translator.atranslate_document(
        HTML_TEXT,
        source_lang="zh-CN",
        target_lang="en",
        format="html",
    )
    print(html_result.text)
    print(f"\nHTML translated text nodes: {len(html_result.chunks)}")


if __name__ == "__main__":
    asyncio.run(main())
